class Solution {
public:
    string originalDigits(string s) {
        int count[26] = {0};
        for (char c : s) {
            count[c - 'a']++;
        }

        int digits[10] = {0};
        digits[0] = count[22]; // z -> zero
        digits[2] = count[6]; // w -> two
        digits[4] = count[20]; // u -> four
        digits[6] = count[23]; // x -> six
        digits[8] = count[7]; // g -> eight

        digits[1] = count[14] - digits[0] - digits[2] - digits[4]; // o
        digits[3] = count[8] - digits[8]; // h
        digits[5] = count[19] - digits[4]; // f
        digits[7] = count[5] - digits[0] - digits[2] - digits[6]; // s
        digits[9] = count[18] - digits[8] - digits[6] - digits[4]; // i

        string result;
        for (int i = 0; i < 10; i++) {
            for (int j = 0; j < digits[i]; j++) {
                result += to_string(i);
            }
        }

        return result;
    }
};
```
